const articles = $('Top Articles').all().map(i => i.json);
let geoInsights = {};
try { geoInsights = JSON.parse($('Read GEO Insights').first().json.Body); } catch(e) {}

const REPO_MAP = {
  'emilingemarkarlsson.com': { repo: 'emilingemarkarlsson/emilingemarkarlsson-astro-theme', base: 'src/content/blog', pathPrefix: '/blog/' },
  'thehockeyanalytics.com': { repo: 'emilingemarkarlsson/tha-website', base: 'src/pages/posts', pathPrefix: '/posts/' }
};

// Pick top EIK article (highest value site)
const eik = articles.filter(a => a.domain === 'emilingemarkarlsson.com')[0];
const tha = articles.filter(a => a.domain === 'thehockeyanalytics.com')[0];
const target = eik || tha;

if (!target) return [{ json: { skip: true } }];

const repo = REPO_MAP[target.domain];
const slug = target.url_path.replace(repo.pathPrefix, '').replace(/\/$/, '');
const filePath = repo.base + '/' + slug + '.md';

return [{ json: { domain: target.domain, views: target.views, slug, filePath, repo: repo.repo, geoInsights: geoInsights.insights || [] } }];

const github = $('Fetch from GitHub').first().json;
if (github.message === 'Not Found') {
  return [{ json: { skip: true, reason: 'File not found: ' + $('Pick Article').first().json.filePath } }];
}
const content = Buffer.from(github.content.replace(/\n/g,''), 'base64').toString('utf8');
const sha = github.sha;
const meta = $('Pick Article').first().json;

// Check if FAQ section already exists
const hasFAQ = /##\s*faq|##\s*vanliga fr[åa]gor|##\s*frequently asked/i.test(content);

return [{ json: { content, sha, hasFAQ, ...meta } }];

const input = $('Decode Content').first().json;
if (input.skip) return [{ json: input }];

const groqResp = $input.first().json;
const raw = groqResp.choices[0].message.content;

let faqMarkdown = '';
let improvNote = '';
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) {
    const parsed = JSON.parse(m[0]);
    faqMarkdown = parsed.faq_markdown || '';
    improvNote = parsed.improvement_note || '';
  }
} catch(e) {}

// Extract FAQ markdown from response if JSON parse failed
if (!faqMarkdown) {
  const faqMatch = raw.match(/(##\s*FAQ[\s\S]*)/i);
  faqMarkdown = faqMatch ? faqMatch[1].trim() : '';
  improvNote = 'FAQ section added';
}

if (!faqMarkdown) return [{ json: { skip: true, reason: 'No FAQ generated' } }];

// Append FAQ to article (replace existing FAQ if present, else append)
let updatedContent;
if (input.hasFAQ) {
  updatedContent = input.content.replace(/##\s*FAQ[\s\S]*/i, faqMarkdown);
} else {
  updatedContent = input.content.trimEnd() + '\n\n' + faqMarkdown + '\n';
}

return [{ json: { ...input, updatedContent, improvNote, faqMarkdown } }];

